  ?term wdt:P31 wd:Q170022 ;
        wdt:P1766 wd:Q190005 ;
        wdt:P1545 ?termNumber .
  FILTER (REGEX(?termNumber, "^[0-9]+$"))
  BIND(xsd:integer(?termNumber) AS ?num)

  ?person p:P39/ps:P39 wd:Q4047513 ;
          p:P39/pq:P2937 ?term .

  OPTIONAL {
    ?person wdt:P21 wd:Q6581072 .
    BIND(wd:Q6581072 AS ?female)
  }
}
GROUP BY ?term ?termNumber ?num
ORDER BY DESC(?num)
